// Create a coupon redemption system where users can apply discount codes
const coupons = {
  "COUPON1": {
    code: "COUPON1",
    discount: 10,
    expirationDate: new Date("2023-01-01"),
    used: false
  },
  "COUPON2": {
    code: "COUPON2",
    discount: 20,
    expirationDate: new Date("2023-01-01"),
    used: false
  }
};

// Check if the coupon is still valid and not expired
function isCouponValid(code) {
  const coupon = coupons[code];
  return !coupon.used && new Date() < coupon.expirationDate;
}

// Verify that the coupon hasn't been used yet
function isCouponUnused(code) {
  const coupon = coupons[code];
  return !coupon.used;
}

// Mark the coupon as used and apply the discount
function useCoupon(code) {
  const coupon = coupons[code];
  coupon.used = true;
  return coupon.discount;
}

// Handle high traffic during sales events by using a queue to process requests
const requestQueue = [];
function handleRequest(request) {
  if (isCouponValid(request.couponCode)) {
    if (isCouponUnused(request.couponCode)) {
      useCoupon(request.couponCode);
      return true;
    } else {
      return false;
    }
  } else {
    return false;
  }
}

// Process requests in the queue
function processQueue() {
  while (requestQueue.length > 0) {
    const request = requestQueue[0];
    if (handleRequest(request)) {
      requestQueue.shift();
    } else {
      break;
    }
  }
}

// Add a new request to the queue
function addRequestToQueue(request) {
  requestQueue.push(request);
}

// Handle incoming requests by adding them to the queue and processing the queue
function handleIncomingRequests() {
  const request = getNextRequest();
  if (request) {
    addRequestToQueue(request);
    processQueue();
  }
}